# -*- coding: utf-8 -*-\nimport os\nimport sys\n\n# Find the files\nresume_suggestions = r'D:\浏览器下载\简历建议.doc'\nresume_pdf = r'D:\浏览器下载\简历--郑茜.pdf'\n\n# Test paths exist\nprint(f"简历建议文件: {os.path.exists(resume_suggestions)}")\nprint(f"简历PDF文件: {os.path.exists(resume_pdf)}")\n\n# Read suggestions\ntry:\n    from docx import Document\n    doc = Document(resume_suggestions)\n    print("=== 简历建议内容 ===")\n    for p in doc.paragraphs:\n        if p.text.strip():\n            print(p.text)\nexcept Exception as e:\n    print(f"简历建议读取失败: {e}", file=sys.stderr)\n\n# Read PDF\ntry:\n    from pypdf import PdfReader\n    reader = PdfReader(resume_pdf)\n    print("\n=== 简历内容 ===")\n    for page in reader.pages:\n        text = page.extract_text()\n        if text.strip():\n            print(text)\nexcept Exception as e:\n    print(f"简历PDF读取失败: {e}", file=sys.stderr)\n\nprint("\n=== Done ===")\n